-- в”Ђв”Ђ Jane App в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based clinic management and EHR software for health and wellness practitioners, offering booking, charting, and billing.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$CAD $54/month$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$501-1,000 employees$q$, company_size),
  headquarters = COALESCE($q$North Vancouver, British Columbia, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Jane App Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Jane App is a Canadian clinic management and EHR platform for health and wellness practitioners. Compare Jane's plans, pricing, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Jane App, commonly known as Jane, is a cloud-based practice management and electronic health record platform built specifically for health and wellness practitioners, including physiotherapists, chiropractors, massage therapists, counselors, naturopaths, and multi-disciplinary clinics. The company was founded by Ali Taylor and Trevor Johnston in North Vancouver, British Columbia, Canada, where it remains headquartered today. The origin story traces back to 2011, when Ali Taylor opened Canopy Integrated Health, a multi-disciplinary clinic, and could not find scheduling and charting software flexible enough to serve multiple practitioner types under one roof; Trevor Johnston, who ran a marketing agency at the time, built the original tool to solve that problem. In 2012 the pair decided to turn the internal tool into a licensable product, and Jane officially launched to outside customers in 2014. Jane has since grown into a substantial company, with employee counts reported between roughly 500 and 1,000 depending on the source and date, serving clinics across Canada, the United States, and other markets. The platform's core offering centers on customizable, client-friendly online booking, flexible multi-practitioner scheduling, fully customizable SOAP-note and charting templates suited to different clinical disciplines, insurance billing and claims management, and integrated payment processing so clinics can handle intake, scheduling, treatment documentation, and payment in a single system. More recent additions include 1:1 and group telehealth appointments, an AI Scribe feature that automatically drafts clinical notes from appointment conversations, automated waitlist management, patient self check-in kiosks, secure messaging and automated email/SMS reminders, timesheets and staff task management, and Jane Websites, a bundled website-building add-on for clinics that want an integrated public-facing site. Jane prices its software in Canadian dollars across three core plans: Balance at CAD $54 per month, aimed at solo practitioners and capped at 20 appointments per month; Practice at CAD $79 per month, which removes the appointment cap and adds unlimited practitioner profiles, unlimited SMS reminders, and staff task management; and Thrive at CAD $99 per month, the top tier, which adds room and equipment scheduling, automated patient self check-in, packages and membership billing, and ratings/reviews and analytics integrations. Adding practitioners beyond the first costs roughly CAD $35 to $79.50 per month each depending on part-time or full-time status, and notable add-ons include unlimited AI Scribe notes for CAD $15 per practitioner per month (5 free notes per month are included on every base plan), group telehealth for CAD $15 per practitioner per month, insurance billing for CAD $20 per month plus small per-staff fees, and Jane Websites for CAD $59 per month per clinic. All plans include unlimited human customer support, custom-branded online booking, secure messaging, intake forms and treatment plans, and 1:1 telehealth. Jane commonly offers a free trial period, frequently promoted as one month free with no credit card required, to let clinics evaluate the platform before committing. Jane's target market is small to mid-sized health and wellness practices, particularly multi-disciplinary clinics that need one system flexible enough to serve several types of practitioners, distinguishing it from many US-centric EHR platforms built around a single specialty. Its main competitors include SimplePractice, a US-focused practice management tool popular with mental health and therapy practices; Cliniko, an Australian-founded competitor with similar multi-discipline clinic features; TheraNest and Practice Better, which lean toward mental health and coaching niches; and WebPT, which specializes specifically in physical therapy. Jane differentiates itself through its clean, modern user interface, native support for a wide range of allied health disciplines within one platform, Canadian data residency options, transparent published pricing (unusual in the category), and a product philosophy built around reducing administrative burden for practitioners rather than maximizing billing codes for insurance-heavy US markets.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e495d174-9d89-4a75-aaca-d48d89a2581f';

