INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Trace visualization$q$, $q$Waterfall and flame-graph views break down exactly where time is spent across a request's path through multiple services.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Service dependency graphs$q$, $q$Automatically generated maps show which services call which, useful for onboarding and impact analysis.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$OpenTelemetry native$q$, $q$Jaeger v2 is built on the OpenTelemetry Collector and accepts OTLP data directly, alongside legacy Jaeger and Zipkin formats.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Pluggable storage$q$, $q$Supports Cassandra, Elasticsearch, OpenSearch, Kafka, and native ClickHouse for scalable, cost-efficient trace storage.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Adaptive sampling$q$, $q$Probabilistic and adaptive sampling strategies keep data volumes manageable in high-throughput production systems.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Root cause analysis$q$, $q$Correlates spans across services to pinpoint the origin of latency spikes and failures.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Broad SDK ecosystem$q$, $q$Instrumentation available for Go, Java, Python, Node.js, C++, and other languages via OpenTelemetry.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Kubernetes-friendly deployment$q$, $q$Ships with Helm charts and an operator pattern for running Jaeger natively on Kubernetes clusters.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Completely free and open source with no usage-based billing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Graduated CNCF project with strong governance and long-term stability$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Deep OpenTelemetry alignment future-proofs instrumentation investments$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Flexible storage backend choices to match existing infrastructure$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Large community and wide adoption across cloud native companies$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Requires self-hosting and ongoing operational maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$No built-in alerting or anomaly detection out of the box$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Storage backend tuning (Cassandra/Elasticsearch) can be operationally complex at scale$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$UI is functional but less polished than commercial APM dashboards$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$No official managed cloud offering directly from the project$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Is Jaeger free to use?$q$, $q$Yes. Jaeger is fully open source under the Apache 2.0 license, with no license fees or usage caps; you only pay for the infrastructure you run it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Who created Jaeger?$q$, $q$Jaeger was created at Uber Technologies, led by engineer Yuri Shkuro, and was open sourced in 2017 before being donated to the Cloud Native Computing Foundation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Does Jaeger support OpenTelemetry?$q$, $q$Yes. Jaeger v2 is built on the OpenTelemetry Collector framework and natively accepts trace data via the OpenTelemetry Protocol (OTLP).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$What storage backends does Jaeger support?$q$, $q$Jaeger supports Cassandra, Elasticsearch, OpenSearch, Kafka as a buffering layer, and, since version 2.18.0, native ClickHouse.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Is Jaeger a managed cloud service?$q$, $q$No. Jaeger is self-hosted software; there is no official managed cloud version, though several vendors offer OTLP-compatible managed tracing backends.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$What is Jaeger commonly used with?$q$, $q$It is typically paired with Prometheus for metrics and a log aggregator such as Loki or the ELK stack to build a complete observability stack for microservices.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Microservices latency debugging$q$, $q$Engineers trace a slow request end-to-end to identify which specific service or downstream call is responsible for added latency.$q$, $q$Backend and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Service dependency mapping$q$, $q$Teams use Jaeger's dependency graphs to understand and document how dozens of microservices interact before major refactors or migrations.$q$, $q$SRE and architecture teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Root cause analysis during incidents$q$, $q$During an outage, on-call engineers use trace data to quickly narrow down which service introduced errors or timeouts.$q$, $q$DevOps and incident response teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under Apache 2.0","Unlimited traces and services","All storage backend options","Community support via GitHub and Slack"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jaeger is an open source distributed tracing system that helps engineering teams understand how requests flow through microservices architectures. Originally built at Uber in 2015 to solve the company's own scaling pains, it was open sourced in 2017 and donated to the Cloud Native Computing Foundation, where it graduated to top-tier project status in 2019 alongside Kubernetes and Prometheus.$q$, $q$The project has since evolved to align tightly with OpenTelemetry, the industry standard for instrumentation, meaning Jaeger now ingests OTLP trace data natively and can be deployed as an OpenTelemetry Collector-based backend. It remains entirely free and self-hosted, run on infrastructure the adopting team controls rather than a vendor's cloud.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jaeger's UI lets engineers drill into a single trace as a waterfall or flame graph, showing exactly which service call added latency or threw an error, alongside a service dependency graph that maps how microservices call one another across the whole system.$q$, $q$Under the hood it supports pluggable storage backends (Cassandra, Elasticsearch, OpenSearch, Kafka, and now ClickHouse), adaptive sampling to control data volume at high traffic, and broad language coverage through OpenTelemetry SDKs for Go, Java, Python, Node.js, C++, and more.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jaeger itself has no pricing: it is licensed under Apache 2.0 and free to run in any environment. Costs come entirely from the infrastructure a team provisions to run the collector, query service, and chosen storage backend, plus optional third-party commercial support.$q$, $q$For teams that don't want to operate Jaeger themselves, several vendors offer managed OpenTelemetry-compatible tracing backends (such as Grafana Cloud Traces) that are wire-compatible with Jaeger's data model, letting organizations start self-hosted and migrate to a managed option later without re-instrumenting their code.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('117d354d-ba1d-4901-852d-f37b6680c972', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Zero-touch deployment$q$, $q$Devices auto-enroll and configure themselves out of the box via integration with Apple Business Manager and Apple School Manager.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Configuration and patch management$q$, $q$Push OS updates, security patches, and configuration profiles across an entire Apple device fleet remotely.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$App deployment$q$, $q$Distribute and manage both custom in-house apps and App Store apps at scale, including licensing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Cloud identity (Jamf Connect)$q$, $q$Bind Apple devices to modern identity providers like Okta, Azure AD, or Google Workspace instead of legacy directory services.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Endpoint security (Jamf Protect)$q$, $q$macOS and mobile-native threat detection, malware protection, and Zero Trust Network Access.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Inventory and compliance reporting$q$, $q$Real-time visibility into device compliance, installed software, and security posture across the fleet.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Education-specific tools (Jamf School)$q$, $q$Classroom management, student device restrictions, and content filtering tailored for K-12 environments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Self-service small business tier$q$, $q$Jamf Now offers an IT-department-free setup for organizations managing fewer than 25 devices.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Deepest, most mature Apple-specific MDM feature set on the market$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Fast day-one support for new macOS, iOS, and iPadOS releases$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Integrated identity (Connect) and endpoint security (Protect) reduce tool sprawl$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Scales from small businesses (Jamf Now) to Fortune 500 enterprises$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Strong presence and purpose-built tooling in education (Jamf School)$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Enterprise pricing is not public and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Apple-only focus means a separate tool is needed for Windows or Android$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Can be costly at scale compared to newer, leaner competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Feature depth adds a learning curve for smaller IT teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Ongoing acquisition by Francisco Partners introduces some uncertainty about future roadmap direction$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$What is Jamf used for?$q$, $q$Jamf is used to enroll, configure, secure, and support fleets of Apple devices, including Mac, iPhone, iPad, and Apple TV, in businesses, schools, and government agencies.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$How much does Jamf cost?$q$, $q$Enterprise pricing for Jamf Pro-based bundles is custom quoted, typically estimated between $3.67 and $12.50 per device per month; Jamf Now for small businesses is free for the first 3 devices, then billed per device per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Is Jamf only for Apple devices?$q$, $q$Yes, Jamf is built exclusively around macOS, iOS, iPadOS, tvOS, and visionOS, though Jamf for Mobile also extends limited support to Android devices.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Who owns Jamf?$q$, $q$Jamf was a publicly traded company on NASDAQ (JAMF) until Francisco Partners completed a $2.2 billion acquisition on January 30, 2026, taking it private.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$What is the difference between Jamf Pro and Jamf Now?$q$, $q$Jamf Pro is the enterprise-grade platform for large, complex device fleets with dedicated IT administration, while Jamf Now is a simplified, self-service tier aimed at small businesses with fewer than 25 employees.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Does Jamf offer a free trial?$q$, $q$Jamf Now offers a 14-day free trial and permanently free management of the first three devices; enterprise Jamf Pro trials are arranged through Jamf's sales team.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Enterprise Apple fleet management$q$, $q$Large organizations use Jamf Pro to zero-touch deploy, configure, patch, and secure thousands of Mac and iOS devices across departments.$q$, $q$Enterprise IT and security teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$K-12 and higher-ed device management$q$, $q$Schools use Jamf School to manage student iPads and Macs, enforce content filtering, and control classroom app access.$q$, $q$School IT administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Small business Apple onboarding$q$, $q$Small companies use Jamf Now to set up and secure a handful of company Macs and iPhones without hiring dedicated IT staff.$q$, $q$Small business owners and lean IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Jamf Now$q$, $q$Free for first 3 devices, then $4/device$q$, $q$monthly$q$, NULL, $q$["Self-service setup, no IT required","App distribution","macOS malware protection","14-day free trial, cancel anytime"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Jamf for Mac$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Jamf Pro device management","Jamf Connect identity","Jamf Protect endpoint security","Zero Trust Network Access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$Jamf for Mobile$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["iOS, iPadOS, and Android management","Mobile threat defense","Zero Trust Network Access","App and content distribution"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jamf is the dominant platform for managing Apple devices in business and education environments, built entirely around macOS, iOS, iPadOS, and tvOS rather than trying to be a generic cross-platform MDM. It began life in 2002 in Eau Claire, Wisconsin as The Casper Suite and has grown into a publicly traded, Minneapolis-headquartered company serving tens of thousands of organizations.$q$, $q$In October 2025 Jamf agreed to be acquired by Francisco Partners for approximately $2.2 billion, with the deal closing January 30, 2026, moving the company from public to private ownership while it retains its brand and product lineup. Its core value proposition is deep, day-one compatibility with new Apple hardware and OS releases, something generalist MDM tools historically lag behind on.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jamf Pro handles zero-touch enrollment through Apple Business Manager, configuration profiles, patch and application deployment, and detailed inventory and compliance reporting for large device fleets. Jamf Connect layers cloud identity on top, binding devices to providers like Okta or Azure AD without a traditional on-prem directory, and Jamf Protect adds macOS and mobile-specific threat detection, malware defense, and Zero Trust Network Access.$q$, $q$For smaller organizations, Jamf Now strips this down into a self-service dashboard usable without dedicated IT staff, while Jamf School adapts the same underlying management engine for classroom and student-device use cases in K-12 and higher education.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jamf does not publish transparent list pricing for its enterprise products; Jamf for Mac and Jamf for Mobile are sold as custom, quote-based subscriptions bundling Jamf Pro, Connect, and Protect, with industry estimates placing per-device costs roughly between $3.67 and $12.50 per month depending on scale and feature selection.$q$, $q$Jamf Now is the exception, with clear self-service pricing: the first three managed devices are free permanently, and additional devices are billed per device per month, with a 14-day free trial and no minimum commitment, making it accessible for small businesses that want to try Apple MDM without a sales negotiation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('924c5694-cfb7-4b06-9d9d-b00e1afadb31', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Peer-to-peer architecture$q$, $q$Messages and calls travel directly between devices using a distributed hash table for discovery, with no central relay server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$End-to-end encryption$q$, $q$All messaging, voice, and video traffic is encrypted end-to-end between participants by default.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Group messaging and conferencing$q$, $q$Supports group text chats and multi-party video conferences alongside one-to-one calls.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$SIP interoperability$q$, $q$Can function as a SIP client, connecting to traditional telephony infrastructure alongside peer-to-peer contacts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$No account personal data required$q$, $q$Accounts are created without a phone number or email, using a distributed identity instead.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Offline and local-network messaging$q$, $q$Devices on the same local network can message and call each other without any internet connection.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Multi-device sync$q$, $q$Swarm-based conversations let a single identity be linked across multiple devices and stay in sync.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Cross-platform availability$q$, $q$Native clients for GNU/Linux, Windows, macOS, iOS, Android, and Android TV.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Completely free with no ads, limits, or paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$True peer-to-peer design means no company holds message content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Backed by the Free Software Foundation as an official GNU package$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Works across all major desktop and mobile platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Can operate entirely offline over a local network$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Smaller user base than mainstream messengers like Signal or WhatsApp makes adoption harder$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Peer-to-peer calls can be less reliable than server-relayed calls behind restrictive NATs or firewalls$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Interface and onboarding are less polished than commercial competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Group features and conferencing are less battle-tested at large scale$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$No official enterprise support contracts beyond community and Savoir-faire Linux consulting$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Is Jami really free?$q$, $q$Yes, Jami is completely free and open source with no subscription fees, ads, or feature limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Who develops Jami?$q$, $q$Jami is developed by Savoir-faire Linux, a Montreal, Canada-based open source software and consulting company, and is an official GNU package backed by the Free Software Foundation.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Does Jami use a central server?$q$, $q$No. Jami uses a distributed hash table for peer discovery and routes messages and calls directly between users' devices, so it has no central server storing conversation content.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$What was Jami previously called?$q$, $q$Jami began as SFLphone in December 2004, was renamed Ring in May 2015, and was renamed again to Jami in December 2018.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$What platforms does Jami support?$q$, $q$Jami is available on GNU/Linux, Windows, macOS, iOS, Android, and Android TV, with multi-device sync for a single account.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$How is Jami different from Signal?$q$, $q$Signal encrypts messages end-to-end but still routes them through centralized servers operated by the Signal Foundation, while Jami eliminates servers from the data path entirely using peer-to-peer connections.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Private peer-to-peer team communication$q$, $q$Privacy-conscious organizations use Jami for internal messaging and calls that never transit a third-party server.$q$, $q$Privacy-focused organizations and free-software communities$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$SIP-compatible calling$q$, $q$Users connect Jami to existing SIP telephony infrastructure for interoperable voice calling alongside peer-to-peer contacts.$q$, $q$IT teams with legacy VoIP systems$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Offline local-network messaging$q$, $q$Teams or households on the same local network use Jami to message and call without needing internet access.$q$, $q$Field teams and offline environments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited messaging, audio, and video calls","Group chats and conferencing","SIP client compatibility","Cross-platform, multi-device support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jami is a free and open source messaging and calling platform built around a genuinely peer-to-peer architecture: conversations travel directly between participants' devices rather than through a company's servers. It is developed by Savoir-faire Linux, a Montreal-based open source firm, and traces its roots to the SFLphone VoIP project launched in December 2004, later renamed Ring in 2015 and finally Jami in 2018.$q$, $q$As an official GNU package backed by the Free Software Foundation, Jami occupies a distinct niche among privacy messengers: rather than merely encrypting traffic that still passes through central servers (as Signal does), Jami eliminates the server from the data path entirely using a distributed hash table for peer discovery, so there is no company that could be compelled to hand over message content because none is ever stored centrally.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jami supports one-to-one and group text messaging, audio and video calls, multi-party video conferencing, and screen sharing, all end-to-end encrypted by default. It can also function as a standard SIP client, letting it interoperate with existing telephony systems, and its swarm-based conversation model keeps multiple linked devices in sync without a server acting as the source of truth.$q$, $q$Because no personal information is required to create an account, and communication can even happen over a local network without internet access, Jami is popular in privacy-sensitive contexts. Its extension system allows optional add-ons like call recording or background blur, and the app is available on GNU/Linux, Windows, macOS, iOS, Android, and Android TV.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jami is entirely free, with no subscription tiers, ads, or feature restrictions of any kind; every capability, including group video calls and file sharing, is available to all users at no cost. This reflects both its GNU/GPLv3 licensing and the fact that it has no central infrastructure to monetize, since calls and messages route directly between users' own devices.$q$, $q$Savoir-faire Linux, the company behind Jami, sustains the project through its broader open source consulting business, community contributions, and free-software grants and sponsorships rather than through Jami itself, which has no paid plan to compare against.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
