INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('23bab05b-2293-4f46-a717-4934ba3b60c5', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Fully offline local inference$q$, $q$Runs open-weight models entirely on-device via llama.cpp, with no internet connection or data transmission required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$In-app model catalog$q$, $q$Browse and download models from families like Llama, Qwen, Gemma, Mistral, and DeepSeek directly inside the app.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$OpenAI-compatible local API server$q$, $q$Exposes local models through an OpenAI-format API so existing tools and scripts can use Jan as a drop-in backend.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Cloud model integration$q$, $q$Optionally connect OpenAI, Anthropic Claude, or Google Gemini using your own API key alongside local models.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Hugging Face integration$q$, $q$Access more than 120 additional models directly from Hugging Face's model hub.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Adjustable model parameters$q$, $q$Fine-tune temperature, context length, and system prompts per conversation or model.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$No telemetry by default$q$, $q$Designed with privacy as a default, not an opt-out, for fully local usage.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Cross-platform desktop app$q$, $q$Available natively for macOS, Windows, and Linux.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Completely free and open source under Apache 2.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Works fully offline with no data leaving the device$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$OpenAI-compatible API makes it a drop-in local backend for developers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Supports both local open-weight models and cloud models in one app$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Large, active community with frequent updates$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Local model quality and speed depend heavily on the user's own hardware$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Larger, more capable models require significant RAM or GPU resources$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Persistent memory across conversations is on the roadmap but not yet available$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Less polished enterprise support compared to commercial AI platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Model management and quantization concepts have a learning curve for non-technical users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Is Jan free to use?$q$, $q$Yes, Jan is completely free and open source under the Apache 2.0 license, with no subscription fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Do I need an internet connection to use Jan?$q$, $q$No. Jan can run entirely offline using locally downloaded open-weight models; an internet connection is only needed if you choose to connect a cloud model API.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Who makes Jan?$q$, $q$Jan is built by Menlo Research, a Singapore-based company founded in 2023 by Daniel Ong and Nicole Zhu.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$What models does Jan support?$q$, $q$Jan supports open-weight models including Llama, Qwen, Gemma, Mistral, and DeepSeek locally, plus cloud models like ChatGPT, Claude, and Gemini via API key.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Can developers build on top of Jan?$q$, $q$Yes, Jan can run as a local server exposing an OpenAI-compatible API, letting developers point existing applications at local models with no code changes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$What platforms does Jan run on?$q$, $q$Jan is available as a native desktop application for macOS, Windows, and Linux.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Private, offline AI chat$q$, $q$Individuals use Jan to chat with AI models without sending any data to external servers, ideal for sensitive personal or business information.$q$, $q$Privacy-conscious individuals and professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Local development and prototyping$q$, $q$Developers use Jan's OpenAI-compatible local server to build and test AI features against local models before switching to production APIs.$q$, $q$Software developers and AI engineers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Regulated and air-gapped environments$q$, $q$Organizations that cannot send data to external AI vendors use Jan to run models entirely within their own infrastructure.$q$, $q$Regulated industries and government or air-gapped teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Free (Local Models)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited local model usage","In-app model catalog and Hugging Face access","OpenAI-compatible local API server","Full offline operation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$Bring Your Own Key (Cloud Models)$q$, $q$Free app, pay provider directly$q$, $q$N/A$q$, NULL, $q$["Connect OpenAI, Anthropic, or Google Gemini API keys","Mix local and cloud models in one interface","No markup from Jan on API usage"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jan is an open source desktop application that lets anyone run AI chat models locally on their own computer, offering a ChatGPT-style interface without requiring cloud access or an API subscription. It is built by Menlo Research, a Singapore company founded in 2023 by Stanford alumni Daniel Ong and Nicole Zhu, with the project quickly growing to over 42,000 GitHub stars and 5 million downloads.$q$, $q$Under the hood, Jan is a Tauri and TypeScript desktop app powered by the llama.cpp inference engine, which lets it run quantized open-weight models efficiently on ordinary consumer hardware. It ships under the Apache 2.0 license, meaning the full source is auditable and free to adapt, including for commercial use.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jan includes an in-app model catalog for downloading open-weight models like Llama, Qwen, Gemma, Mistral, DeepSeek, and GPT-OSS, with over 120 models accessible via Hugging Face integration, and it works entirely offline with no telemetry by default. Users can also connect it to cloud APIs such as OpenAI, Anthropic Claude, or Google Gemini using their own API keys, mixing local and cloud inference inside one chat interface.$q$, $q$For developers, Jan can run as a local server that mimics the OpenAI API format, so existing applications built against OpenAI's API can point at Jan and use local models as a drop-in substitute with no code rewrite, which has made it popular for prototyping and privacy-sensitive development workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jan is completely free and open source, with no subscription tiers, seat-based pricing, or feature paywalls; every capability, including the model catalog, local API server, and cloud model integrations, is available at no cost.$q$, $q$The only costs a user might incur are indirect: sufficiently powerful hardware to run larger local models comfortably, or usage fees charged by third-party providers like OpenAI or Anthropic if the user chooses to connect their own API key for cloud models within Jan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9cc30e55-3b4a-4b57-88bd-393a5082ac87', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
