INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Online booking$q$, $q$Custom-branded, client-facing scheduling that lets patients book appointments directly.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Customizable charting$q$, $q$SOAP-note and treatment plan templates adaptable to different clinical disciplines under one system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Telehealth$q$, $q$Built-in 1:1 and group video appointments without needing a separate telehealth tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$AI Scribe$q$, $q$Automatically drafts clinical documentation from appointment conversations, with free and unlimited usage tiers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Insurance billing$q$, $q$Manages insurance claims and billing workflows as an add-on module.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Integrated payments$q$, $q$Built-in invoicing and payment processing tied directly to appointments and treatment plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Waitlist and self check-in$q$, $q$Automated waitlist management and patient self check-in kiosks on higher-tier plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Staff management$q$, $q$Timesheets and task management tools for clinic administrative staff.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Transparent, published pricing unlike many competitors that require sales calls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Supports many allied health disciplines natively in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Modern, clean interface that is easy for both staff and patients to use$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Built-in AI Scribe reduces charting time for practitioners$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Free trial available with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Pricing is listed in Canadian dollars, adding currency conversion friction for some markets$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Additional practitioners and add-ons can meaningfully increase monthly cost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Balance plan's 20-appointment cap may be limiting for busier solo practices$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Some advanced features (self check-in, memberships) are reserved for the top Thrive tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Insurance billing depth may not match specialty-specific US platforms for complex claims$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$What is Jane App used for?$q$, $q$Jane App is practice management and EHR software used by health and wellness practitioners to handle online booking, scheduling, charting, telehealth, billing, and payments.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$How much does Jane App cost?$q$, $q$Jane's core plans start at CAD $54 per month (Balance), with Practice at CAD $79 per month and Thrive at CAD $99 per month, plus per-practitioner and add-on fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Who founded Jane App?$q$, $q$Jane App was founded by Ali Taylor and Trevor Johnston in North Vancouver, British Columbia, Canada, launching commercially in 2014.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Does Jane App offer a free trial?$q$, $q$Yes, Jane commonly offers a free trial period, often one month, with no credit card required to start.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$What types of practitioners use Jane App?$q$, $q$Jane is used by physiotherapists, chiropractors, massage therapists, counselors, naturopaths, and other allied health and wellness practitioners, especially multi-disciplinary clinics.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Does Jane App include telehealth?$q$, $q$Yes, all plans include 1:1 telehealth appointments, with group telehealth available as a paid add-on.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Multi-disciplinary clinic management$q$, $q$Clinics with several practitioner types use Jane's flexible charting and scheduling to run the whole practice from one system.$q$, $q$Multi-disciplinary health and wellness clinics$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Solo practitioner scheduling and billing$q$, $q$Independent practitioners use Jane's Balance plan for booking, charting, and payments without enterprise-level cost.$q$, $q$Solo health and wellness practitioners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Telehealth and remote care delivery$q$, $q$Practices use Jane's built-in telehealth to see patients remotely without integrating a third-party video tool.$q$, $q$Practices offering remote or hybrid care$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Balance$q$, $q$CAD $54$q$, $q$monthly$q$, NULL, $q$["Online booking and scheduling","Charting and treatment plans","Integrated payments","Up to 20 appointments per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Practice$q$, $q$CAD $79$q$, $q$monthly$q$, NULL, $q$["Unlimited appointments","Unlimited SMS reminders","Timesheets and task management","Wait list functionality"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$Thrive$q$, $q$CAD $99$q$, $q$monthly$q$, NULL, $q$["Rooms and equipment scheduling","Patient self check-in","Packages and memberships","Ratings, reviews, and analytics integration"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jane App is a cloud-based clinic management and EHR platform built for health and wellness practitioners such as physiotherapists, massage therapists, chiropractors, and counselors. It was co-founded by Ali Taylor and Trevor Johnston in North Vancouver, Canada, after Taylor struggled to find flexible enough software for her own multi-disciplinary clinic, Canopy Integrated Health, in 2011; the tool Johnston built for her became a commercial product in 2012 and launched publicly in 2014.$q$, $q$Jane has grown from a single-clinic solution into a company with several hundred employees serving practices across Canada, the United States, and beyond, while staying focused on its original mission of supporting multi-disciplinary practices with one flexible system rather than specialty-specific software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jane combines client-friendly online booking, flexible scheduling across multiple practitioners and rooms, fully customizable charting and SOAP-note templates, insurance billing, and integrated payment processing in a single platform. Newer additions include telehealth (both 1:1 and group), an AI Scribe that drafts clinical notes automatically, automated waitlists, and patient self check-in.$q$, $q$Administrative tools like staff timesheets, task management, secure messaging, and automated appointment reminders round out the platform, and clinics can add on Jane Websites for an integrated public-facing site, reducing the number of separate tools a practice needs to run day-to-day operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jane publishes transparent pricing in Canadian dollars across three plans: Balance at CAD $54 per month for solo practitioners with a 20-appointment cap, Practice at CAD $79 per month with unlimited appointments, and Thrive at CAD $99 per month adding automation, self check-in, and membership billing. Additional practitioners cost roughly CAD $35 to $79.50 per month each.$q$, $q$Add-ons extend the core plans, including unlimited AI Scribe notes at CAD $15 per practitioner per month, group telehealth at CAD $15 per practitioner per month, insurance billing at CAD $20 per month, and Jane Websites at CAD $59 per month. Jane frequently offers a free trial, commonly one month, so clinics can test the platform before subscribing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e495d174-9d89-4a75-aaca-d48d89a2581f', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Modular plugin architecture$q$, $q$Core WebRTC handling is separated from application logic, which lives in swappable server-side plugins.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$VideoRoom SFU$q$, $q$Official plugin implementing a full multi-party video conferencing room as a selective forwarding unit.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$SIP gateway$q$, $q$Bridges WebRTC clients to traditional SIP telephony infrastructure for interoperable voice calling.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$AudioBridge$q$, $q$Mixes audio from multiple participants for audio-only conferencing use cases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Streaming plugin$q$, $q$Supports one-to-many live broadcast scenarios such as webinars or live events.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Recording and playback$q$, $q$Recordplay plugin captures and replays WebRTC sessions for later review.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Small footprint$q$, $q$Designed to run efficiently on modest hardware as well as scale to large cloud deployments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$JSON signaling API$q$, $q$Simple, well-documented JSON protocol for browsers and clients to communicate with the server.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Completely free and open source with no usage-based fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Modular plugin system gives developers granular control over functionality$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Native SIP gateway support that many competing SFUs lack$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Long production track record and active maintenance by its original authors$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Commercial support available directly from Meetecho when needed$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Requires significant developer effort to build a finished product on top of it$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$No official managed cloud hosting option from Meetecho$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Lower-level API means a steeper learning curve than fully managed video SDKs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Documentation, while solid, assumes real-time media and networking expertise$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Scaling and operating in production requires WebRTC infrastructure knowledge$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Is Janus free to use?$q$, $q$Yes, Janus is free and open source under the GNU General Public License, with no licensing fees or usage caps.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Who created Janus?$q$, $q$Janus was created by Meetecho, an Italian company founded in 2009 by Alessandro Amirante, Lorenzo Miniero, and Tobia Castaldi, with Miniero as its principal author.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$What is Janus used for?$q$, $q$Janus is used to build custom real-time video conferencing, live streaming, webinar, and SIP-to-WebRTC bridging applications.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Is Janus a finished conferencing app?$q$, $q$No, Janus is a low-level WebRTC gateway and infrastructure component; developers build their own client and server logic on top of it using its plugin system.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Does Janus support SIP calling?$q$, $q$Yes, its official SIP plugin bridges WebRTC clients to traditional SIP telephony infrastructure.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Can I get commercial support for Janus?$q$, $q$Yes, Meetecho, the company behind Janus, offers commercial consulting, plugin development, and support contracts.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Custom video conferencing platforms$q$, $q$Companies use Janus's VideoRoom plugin as the SFU foundation for building their own branded conferencing products.$q$, $q$Software companies building real-time communication products$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Live streaming and webinars$q$, $q$Organizations use Janus's Streaming plugin to broadcast one-to-many live video for events or education.$q$, $q$EdTech and live-event platforms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$SIP-to-WebRTC bridging$q$, $q$Telecom and enterprise teams use Janus's SIP plugin to let browser-based clients call into existing telephony systems.$q$, $q$Telecom and enterprise communications teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under GPL","All official plugins included","Unlimited self-hosted deployment","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$Meetecho Commercial Support$q$, $q$Custom pricing$q$, $q$contract$q$, NULL, $q$["Consulting and deployment assistance","Custom plugin development","Direct support from Janus's original authors"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Janus is a free, open source WebRTC gateway server that gives developers low-level building blocks for real-time audio, video, and data communication rather than a finished conferencing product. It was created by Meetecho, an Italian company founded in 2009 as a spin-off of the University of Naples Federico II, and is led technically by Lorenzo Miniero, Meetecho's chairman and Janus's principal author.$q$, $q$Rather than shipping as an opinionated video conferencing app, Janus positions itself as infrastructure: developers build their own client applications and server logic around Janus's core WebRTC handling, using its modular plugin system to add exactly the functionality (conferencing, streaming, SIP, recording) that a given product needs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Janus core, written in C, handles ICE negotiation, DTLS/SRTP encryption, and RTP/RTCP media relay, exposing a JSON-based signaling API that browsers and other WebRTC clients use to talk to the server. Application behavior is implemented through official plugins: VideoRoom for multi-party video conferencing, AudioBridge for audio mixing, Streaming for one-to-many broadcast, Recordplay for session recording and playback, and SIP for bridging WebRTC clients into traditional telephony.$q$, $q$This plugin-based design gives Janus a small footprint that can run on modest hardware for lightweight deployments, while still scaling up to full cloud-based video infrastructure for larger production systems, making it a popular choice for teams that want fine-grained control over their real-time media stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Janus itself is entirely free and open source under the GNU General Public License, with no cost to download, self-host, or modify the software, and no usage-based fees regardless of scale.$q$, $q$Meetecho, the company behind Janus, generates revenue not from the software itself but from separate commercial services: consulting, custom plugin development, and support contracts for organizations that want expert help deploying and operating Janus in production.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fabd1ffb-a233-4c33-bb07-50f94bcfa2d0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Three-column reading interface$q$, $q$Classic feed reader layout with categories, article list, and full content view side by side.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Readability content extraction$q$, $q$Pulls full article text for feeds that only publish truncated summaries.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Queue-based crawler$q$, $q$Periodically polls subscribed feeds for new articles using a background job queue.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Unread and error filtering$q$, $q$Quickly filter the feed list to show only unread items or feeds currently failing to fetch.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Mobile-responsive design$q$, $q$Interface adapts for comfortable reading on tablets and phones as well as desktop.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Self-hosted deployment$q$, $q$Runs on a user's own server, commonly via Docker, for full control over subscription data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Python/Flask backend$q$, $q$Built with Flask and SQLAlchemy for database flexibility and straightforward customization.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$ReactJS frontend$q$, $q$Single-page-application interface built with React for a responsive feel.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Completely free and open source with no hidden costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Self-hosted, giving users full control over their reading data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Readability integration cleans up feeds with truncated content$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Mobile-responsive interface works well on phones and tablets$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Simple, effective three-column layout that's easy to learn$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Maintained largely by a single developer, with a slower and less predictable update cadence$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Smaller community and plugin ecosystem than Tiny Tiny RSS or FreshRSS$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Requires basic server administration knowledge to self-host$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$No official mobile apps, only a responsive web interface$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$No commercial support option if something breaks in production$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Is JARR free?$q$, $q$Yes, JARR is completely free and open source; the only cost is the server infrastructure you choose to host it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$What does JARR stand for?$q$, $q$JARR stands for Just Another RSS Reader, a self-hosted RSS and Atom feed aggregator.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Who created JARR?$q$, $q$JARR is maintained by a developer known as jaesivsm and began as a fork of Cedric Bonhomme's Newspipe project.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Do I need to self-host JARR?$q$, $q$Yes, JARR is designed to be self-hosted, typically via Docker, though a public demo instance is available at jarr.info to try it first.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$What technology is JARR built with?$q$, $q$JARR's backend is built with Python 3, Flask, and SQLAlchemy, with a ReactJS frontend.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Does JARR have mobile apps?$q$, $q$JARR does not have dedicated native mobile apps, but its web interface is mobile-responsive for use on phones and tablets.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Self-hosted news aggregation$q$, $q$Individuals run their own JARR instance to follow blogs and news sites without relying on a third-party feed reader service.$q$, $q$Self-hosting enthusiasts and privacy-conscious readers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Home lab service stack$q$, $q$Sysadmins add JARR to a broader home-lab stack of self-hosted services alongside tools like password managers or media servers.$q$, $q$Home lab and sysadmin communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Reading truncated feeds in full$q$, $q$Users follow publications that only post partial content in their feeds, relying on JARR's Readability integration to read full articles inline.$q$, $q$Heavy blog and news readers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited feeds and articles","Readability content extraction","Mobile-responsive interface","Full source code access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$JARR (Just Another RSS Reader) is a free, open source, self-hosted RSS and Atom feed aggregator that lets users follow blogs and news sites from a single web interface they fully control. It began as a fork of Cedric Bonhomme's Newspipe project and is now maintained by a developer known as jaesivsm, distributed openly on GitHub for anyone to self-host.$q$, $q$As a community-maintained, single-developer-led project rather than a commercial product, JARR appeals to self-hosting enthusiasts and technically comfortable users who value data ownership and independence from centralized feed reader services like Feedly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$JARR presents a classic three-column reading layout: categories and feeds on the left, an article list in the middle, and full article content on the right. For feeds that only publish truncated summaries, it uses Readability-based content extraction to pull and display the full article text inside the app itself.$q$, $q$A queue-based crawler periodically polls subscribed feeds for new content, and filtering options let users quickly surface feeds with unread items or fetch errors. The interface is mobile-responsive for use on tablets and phones, and the app is built on a Python 3 and Flask backend with a ReactJS frontend.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$JARR is entirely free and open source, with no license fees, subscription tiers, or paid features; the only cost involved is whatever server or hosting infrastructure a user chooses to run it on, typically via Docker on a home server or low-cost VPS.$q$, $q$There is no commercial entity behind JARR selling support contracts or hosted plans, so users rely on the public GitHub repository, documentation, and community for setup help; a public jarr.info instance is available to try the reading experience before self-hosting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1030679b-2caa-4c26-9774-5521af246bfb', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
