INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Canvas content workspace$q$, $q$Collaborative surface for drafting and editing long-form and short-form content with AI assistance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Brand Voice and Knowledge$q$, $q$Encodes a company's tone, style, and proprietary facts so AI output stays consistent and accurate.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$AI marketing agents$q$, $q$Pre-built agents automate workflows like blog writing, ad copy, and social content generation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$No-code custom AI Agent builder$q$, $q$Business plan feature letting teams design their own automated content workflows without code.$q$, 3);
