INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$GEO and translation agents$q$, $q$Advanced Business-tier agents for generative engine optimization and multilingual content.$q$, 6);
