INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Output quality still requires human editing and brand review for best results$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$How much does Jasper cost?$q$, $q$Jasper's Pro plan costs $59 per seat per month billed annually, or $69 per month billed monthly; the Business plan uses custom pricing with a 12-month minimum commitment.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Who founded Jasper?$q$, $q$Jasper was founded in 2021 in Austin, Texas by Dave Rogenmoser, JP Morgan, and Chris Hull, who previously built the Y Combinator-backed startup Proof.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Was Jasper called something else before?$q$, $q$Yes, Jasper originally launched as Jarvis before being renamed to Jasper in 2022 following a trademark dispute.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$How much funding has Jasper raised?$q$, $q$Jasper has raised approximately $131 million, including a $125 million Series A in October 2022 at a $1.5 billion valuation led by Insight Partners.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Does Jasper offer a free trial?$q$, $q$Yes, Jasper offers a 7-day free trial for prospective customers to evaluate the platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Who uses Jasper?$q$, $q$Jasper is used by marketing teams ranging from solo creators and small agencies to large enterprises, with close to 20 percent of the Fortune 500 among its customers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Brand-consistent content production$q$, $q$Marketing teams use Jasper's Brand Voice and Knowledge features to produce on-brand blog posts, ads, and social content at scale.$q$, $q$In-house marketing and content teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Automated marketing workflows$q$, $q$Teams deploy Jasper's AI Agents to automate repetitive tasks like drafting ad variations or blog outlines.$q$, $q$Growth and performance marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Enterprise content governance$q$, $q$Large organizations use Jasper's Business plan for API access, SSO, and admin controls to manage AI content generation across many contributors.$q$, $q$Enterprise marketing departments$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Pro$q$, $q$$59/seat (annual) or $69/seat (monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Canvas content platform","Core marketing AI agents","2 Brand Voices, 5 Knowledge assets, 3 Audiences","Image generation and editing","Browser extension and integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$Business$q$, $q$Custom pricing$q$, $q$annual, 12-month minimum$q$, NULL, $q$["Unlimited seats","Advanced agents (GEO, translation, research)","No-code custom AI Agent builder","API access","SSO, SCIM, and enterprise governance"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jasper is an AI content generation platform built specifically for marketing teams, helping them produce blog posts, ad copy, social content, emails, and images that stay consistent with a brand's voice. It was founded in Austin, Texas in 2021 by Dave Rogenmoser, JP Morgan, and Chris Hull, who pivoted from an earlier startup called Proof after experimenting with OpenAI's GPT-3 API in 2020.$q$, $q$Originally launched as Jarvis before a 2022 rename, Jasper became one of the fastest companies in history to reach unicorn status, closing a $125 million Series A at a $1.5 billion valuation led by Insight Partners in October 2022. By 2024 it served over 100,000 businesses, including nearly 20 percent of the Fortune 500.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jasper's core workspace, Canvas, lets teams draft and edit content collaboratively with AI assistance, grounded by Brand Voice profiles, Knowledge assets that encode company-specific facts, and Audience definitions that tailor messaging by customer segment. On top of Canvas, pre-built AI Agents automate specific marketing workflows like blog writing and ad copy, with more advanced agents for GEO optimization, translation, and research available on higher tiers.$q$, $q$The platform also includes AI image generation and editing, a browser extension for using Jasper across the web, and integrations with tools like Google Docs, WordPress, Surfer SEO, and HubSpot, plus a no-code custom AI Agent builder for teams that want to design their own automated content workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d87ead8b-8c90-424b-ae07-9b4003510b45', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jasper offers two public plans: Pro at $59 per seat per month billed annually (or $69 billed monthly), which includes Canvas, core agents, image generation, and a limited number of Brand Voices, Knowledge assets, and Audiences, capped at a single seat. A 7-day free trial is available to test the platform before subscribing.$q$, $q$The Business plan uses custom, quote-based pricing with a required 12-month minimum commitment, and unlocks unlimited seats, advanced agents, the no-code AI Agent builder, API access, and enterprise governance features like SSO, SCIM, and dedicated account management, aimed at larger marketing organizations. A 20 percent discount is available for verified nonprofits.$q$]::text[], 2);
